/* ===== first view image fade in ===== */
(function () {

    const $firstTitle = $('#first-title');

    if (!$firstTitle.length) return;

    const img = $firstTitle.get(0);

    const showImage = () => {
        $firstTitle.addClass('is-loaded');
    };

    // キャッシュ済み対策
    if (img.complete) {
        showImage();
    } else {
        img.addEventListener('load', showImage);
    }

})();



// ギャラリーページ説明表示切替
document.addEventListener('DOMContentLoaded', () => {
    // すべての .item-bird-name を取得
    const toggles = document.querySelectorAll('.item-bird-name');

    toggles.forEach(toggle => {
        toggle.addEventListener('click', () => {
            // クリックされた要素のすぐ次の兄弟要素（.item-text-desc）を取得
            const content = toggle.nextElementSibling;

            // コンテンツが存在する場合のみ処理を実行
            if (content && content.classList.contains('item-text-desc')) {
                // 説明文の表示/非表示を切り替え
                content.classList.toggle('is-open');
                // 矢印の回転用にタイトル側にもクラスを切り替え
                toggle.classList.toggle('is-active');
            }
        });
    });
});



